@implements IAsyncDisposable
@inject IJSRuntime JS

@ChildContent

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public int TimeoutSeconds { get; set; } = 300;
    [Parameter] public EventCallback OnIdle { get; set; }
    [Parameter] public EventCallback OnActive { get; set; }

    private IJSObjectReference? _module;
    private IJSObjectReference? _tracker;
    private DotNetObjectReference<UserActivityTracker>? _dotNetRef;

    private bool _isIdle;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;

        _dotNetRef = DotNetObjectReference.Create(this);
        _module = await JS.InvokeAsync<IJSObjectReference>(
            "import", "./Components/UserActivityTracker.razor.js");
        _tracker = await _module.InvokeAsync<IJSObjectReference>(
            "createTracker", _dotNetRef, TimeoutSeconds * 1000);
    }

    [JSInvokable]
    public async Task OnIdleCallback()
    {
        if (_isIdle) return;
        _isIdle = true;
        await OnIdle.InvokeAsync();
    }

    [JSInvokable]
    public async Task OnActiveCallback()
    {
        if (!_isIdle) return;
        _isIdle = false;
        await OnActive.InvokeAsync();
    }

    public async ValueTask DisposeAsync()
    {
        if (_tracker is not null)
        {
            try { await _tracker.InvokeVoidAsync("dispose"); } catch (JSDisconnectedException) { }
            try { await _tracker.DisposeAsync(); } catch (JSDisconnectedException) { }
        }
        if (_module is not null)
        {
            try { await _module.DisposeAsync(); } catch (JSDisconnectedException) { }
        }
        _dotNetRef?.Dispose();
    }
}

export function createTracker(dotNetRef, timeoutMs) {
    let timerId = null;
    let isIdle = false;

    const events = ['mousemove', 'keydown', 'click', 'scroll'];

    function resetTimer() {
        if (isIdle) {
            isIdle = false;
            dotNetRef.invokeMethodAsync('OnActiveCallback');
        }
        clearTimeout(timerId);
        timerId = setTimeout(() => {
            isIdle = true;
            dotNetRef.invokeMethodAsync('OnIdleCallback');
        }, timeoutMs);
    }

    for (const event of events) {
        document.addEventListener(event, resetTimer, { passive: true });
    }

    // Start the initial timer
    timerId = setTimeout(() => {
        isIdle = true;
        dotNetRef.invokeMethodAsync('OnIdleCallback');
    }, timeoutMs);

    return {
        dispose() {
            clearTimeout(timerId);
            for (const event of events) {
                document.removeEventListener(event, resetTimer);
            }
        }
    };
}

